      },
      {
        "level": 3,
        "level_name": "Advanced",
        "level_description": "Analyzes ingredient properties to select optimal cutting techniques and knife types; mentors junior staff on proper form and efficiency while maintaining precision under high-volume service pressure."
      }
    ]
  },
  {
    "skill_name": "Dry Heat Cooking",
    "category": "Culinary Technique",
    "cluster": "Heat & Cooking Methods",
    "skill_description": "Proficiency in dry heat methods including roasting, grilling, sautéing, and frying to achieve correct texture and flavour.",
    "levels": [
      {
        "level": 1,
        "level_name": "Foundational",
        "level_description": "Follows standardized dry heat cooking procedures (temperature, timing, pan position) for assigned recipes; produces acceptable results under observation but lacks confidence in troubleshooting temperature or timing variations."
      },
      {
        "level": 2,
        "level_name": "Developing",
        "level_description": "Independently applies dry heat methods to achieve consistent browning, caramelization, and target doneness; adjusts heat and cooking time based on ingredient size and type with minimal supervision required."
      },
      {
        "level": 3,
        "level_name": "Advanced",
        "level_description": "Evaluates ingredient composition and desired flavor outcomes to optimize temperature control and timing; mentors others on technique refinement and troubleshoots edge cases (e.g., uneven browning, inadequate texture) to maintain consistency across service."
      }
    ]
  },
  {
    "skill_name": "Moist Heat Cooking",
    "category": "Culinary Technique",
    "cluster": "Heat & Cooking Methods",
    "skill_description": "Proficiency in moist heat methods including braising, poaching, steaming, and simmering to achieve the correct result.",
    "levels": [
      {
        "level": 1,
        "level_name": "Foundational",
        "level_description": "Follows documented moist heat cooking procedures (liquid ratio, temperature, duration) for standard preparations; produces acceptable results with direct guidance but requires re-cooking when liquid levels or heat settings deviate from recipe."
      },
      {
        "level": 2,
        "level_name": "Developing",
        "level_description": "Independently executes braising, poaching, and steaming to achieve tender texture and proper flavor extraction; monitors cooking progress and makes adjustments to maintain liquid levels and gentle simmer without oversight."
      },
      {
        "level": 3,
        "level_name": "Advanced",
        "level_description": "Analyzes protein and vegetable properties to select appropriate moist heat method and liquid base; refines brasing liquids and cooking times to maximize flavor development and coaches team on technique consistency and ingredient-specific variations."
      }
    ]
  },
  {
    "skill_name": "Taste & Seasoning",
    "category": "Culinary Technique",
    "cluster": "Flavour & Seasoning",
    "skill_description": "Ability to evaluate and balance flavours, seasoning, and seasoning adjustments throughout the cooking process.",
    "levels": [
      {
        "level": 1,
        "level_name": "Foundational",
        "level_description": "Identifies basic flavor profiles (salt, sweet, acid, spice) and follows recipe seasoning guidelines; tastes dishes under supervision but relies on established formulas rather than independent judgment for adjustment."
      },
      {
        "level": 2,
        "level_name": "Developing",
        "level_description": "Independently tastes and seasons dishes at multiple cooking stages, making incremental adjustments to balance salt, acid, and spice; demonstrates consistent palate calibration aligned with restaurant standards."
      },
      {
        "level": 3,
        "level_name": "Advanced",
        "level_description": "Evaluates complex flavor interactions and ingredient variables to achieve signature seasoning profiles; mentors staff on palate development and establishes seasoning protocols that ensure consistency across stations and services."
      }
    ]
  },
  {
    "skill_name": "Sauce & Stock Preparation",
    "category": "Culinary Technique",
    "cluster": "Flavour & Seasoning",
    "skill_description": "Skill in producing foundational stocks, mother sauces, and derivative sauces to classical and modern standards.",
    "levels": [
      {
        "level": 1,
        "level_name": "Foundational",
        "level_description": "Follows established stock and mother sauce formulas (ingredients, ratio, cooking time) with direct supervision; produces acceptable results but lacks understanding of ingredient rationale and requires re-working when yields or clarification fail."
      },
      {
        "level": 2,
        "level_name": "Developing",
        "level_description": "Independently produces stocks and mother sauces to specification with proper yield, clarity, and flavor; executes roux-based, emulsion, and reduction sauces with correct technique and implements derivative variations per recipe."
      },
      {
        "level": 3,
        "level_name": "Advanced",
        "level_description": "Optimizes stock recipes based on ingredient quality and desired flavor intensity; develops derivative sauces that balance classical technique with modern presentations and trains junior staff on troubleshooting common failures (separation, over-reduction, inadequate body)."
      }
    ]
  }
]"}

